#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  sqlgen::sqlite::connect(db_path)
      .and_then(sqlgen::write(records))
      .value();
}

void modify_eas_records_by_id(const std::string& table_name,
                               int record_id,
                               const std::string& col_name,
                               const std::string& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Build the SQL UPDATE statement manually for flexibility
  std::string sql = "UPDATE " + table_name + " SET " + col_name + " = ?";

  // Determine the primary key column name based on table
  std::string pk_column;
  if (table_name == "Student") {
    pk_column = "SNo";
    sql += " WHERE " + pk_column + " = ?";
  } else if (table_name == "Course") {
    pk_column = "CID";
    sql += " WHERE " + pk_column + " = " + std::to_string(record_id);
  } else if (table_name == "Score") {
    pk_column = "ScID";
    sql += " WHERE " + pk_column + " = " + std::to_string(record_id);
  } else if (table_name == "Major") {
    pk_column = "MID";
    sql += " WHERE " + pk_column + " = " + std::to_string(record_id);
  }

  sqlgen::exec(conn, sql, new_value).value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  if (table_name == "Student") {
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Student> | where("SNo"_c == record_id))
        .value();
  } else if (table_name == "Course") {
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Course> | where("CID"_c == std::stoul(record_id)))
        .value();
  } else if (table_name == "Score") {
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Score> | where("ScID"_c == std::stoul(record_id)))
        .value();
  } else if (table_name == "Major") {
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Major> | where("MID"_c == std::stoul(record_id)))
        .value();
  }
}
