  };

  struct Course {
    sqlgen::PrimaryKey<int> CID;
    std::string CName;
    rfl::Default<std::optional<int>, 1> Term;
    std::optional<int> CTime;
    rfl::Default<float, rfl::Literal<"0">> Credit;
