TEST(sqlite, query_active_users_posts) {
  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Post>(conn);
  drop<User>(conn);
  create_table<User>(conn);
  create_table<Post>(conn);

  insert(conn, std::vector<User>{{1, "alice"}, {2, "bob"}, {3, "carol"}});
  insert(conn, std::vector<Post>{{1, 1, "2025-12-30 00:00:00"},
                                 {2, 1, "2024-01-01 00:00:00"},
                                 {3, 2, "2025-12-20 00:00:00"},
                                 {4, 3, "2023-01-01 00:00:00"}});

  auto res = query_active_users_posts();
  // Recent window uses now-30 days; our recent entries are 2025-12-01 and 2025-12-10 relative to current date
  ASSERT_GE(res.size(), 2u);
}

