namespace query_active_users_posts {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to SQLite database
    auto db = sqlgen::sqlite::Database("test_db.sqlite");
    db.connect();

    // Create User and Post tables
    db.create_table<User>();
    db.create_table<Post>();

    // Create a view for active users who posted between 2025-12-01 and 2025-12-31
    db.create_view_as<ActiveUser>(
        db.select("user_id"_f, "username"_f)
          .distinct()
          .from<User>("u")
          .inner_join<Post>("p")
          .on("u.user_id = p.user_id"_sql)
          .where("p.created_at >= DATE('2025-12-01') AND p.created_at <= DATE('2025-12-31')"_sql)
    );

    // Query the view and return results
    return db.select<ActiveUser>().execute();
}

}  // namespace query_active_users_posts
