  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create tables if they don't exist
  conn.create_table<Customer>(IfNotExists());
  conn.create_table<Product>(IfNotExists());
  conn.create_table<Order>(IfNotExists());
  conn.create_table<OrderItem>(IfNotExists());

  // 3. Query the database with JOIN operations
  const auto sql = R"(
    SELECT p.name as product_name, o.order_date, oi.quantity
    FROM Customer c
    JOIN "Order" o ON c.customer_id = o.customer_id
    JOIN OrderItem oi ON o.order_id = oi.order_id
    JOIN Product p ON oi.product_id = p.product_id
