  drop<Sale>(conn);
  drop<Product>(conn);
  create_table<Product>(conn);
  create_table<Sale>(conn);

  // Categories: A, B; A should pass HAVING (>5000), B should not
  Product pa{.product_id = 1, .category = "A"};
  Product pb{.product_id = 2, .category = "B"};
  insert(conn, std::vector{pa, pb});

  // Sales: A total amount 6000 (qty 10 + 20), B total amount 4000 (qty 5)
  Sale s1{.sale_id = 1, .product_id = 1, .quantity = 10, .amount = 2000.0};
  Sale s2{.sale_id = 2, .product_id = 1, .quantity = 20, .amount = 4000.0};
