struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Open SQLite database connection
    auto session = sqlgen::sqlite::Session("test_db.sqlite");

    // Execute the SQL query with JOIN, GROUP BY, and HAVING
    const auto sql = R"(
        SELECT p.category, SUM(s.quantity) as total_qty, SUM(s.amount) as total_amt
        FROM Product p
        INNER JOIN Sale s ON p.product_id = s.product_id
        GROUP BY p.category
        HAVING total_amt > 5000
    )";

    // Execute query and get results as ProductSalesReport, then convert to CategoryReport
    auto results = session.execute<std::vector<ProductSalesReport>>(sql);

    // Convert ProductSalesReport to CategoryReport
    std::vector<CategoryReport> reports;
    reports.reserve(results.size());

    for (const auto& row : results) {
        reports.push_back(CategoryReport{
            .category = row.category,
            .total_qty = row.total_qty,
            .total_amt = row.total_amt
        });
    }

    return reports;
}

