#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_create_trigger_audit_log {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct AuditLog {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> log_id;
  std::string table_name;
  int record_id;
  std::string action;
  sqlgen::DateTime timestamp;
};

/**
 * Function: Create a trigger for auditing changes on Product table.
 * 
 * @return true if trigger creation succeeds, false otherwise
 */
bool create_trigger_audit_log() {
  using namespace sqlgen;

  const auto trigger_sql = R"(
CREATE TRIGGER IF NOT EXISTS audit_product_update
AFTER UPDATE ON Product
BEGIN
    INSERT INTO AuditLog (table_name, record_id, action, timestamp)
    VALUES ('Product', OLD.product_id, 'UPDATE', CURRENT_TIMESTAMP);
END;
)";

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
                    .and_then(create_table<Product> | if_not_exists)
                    .and_then(create_table<AuditLog> | if_not_exists)
                    .and_then(exec(trigger_sql));

  return result.has_value();
}

}  // namespace schema_create_trigger_audit_log
```

This implementation:

1. **Connects to the SQLite database** `test_db.sqlite` using `sqlgen::sqlite::connect()`
2. **Creates the Product and AuditLog tables** if they don't exist (using the `if_not_exists` modifier)
3. **Executes raw SQL** to create the trigger using `exec()`
4. **Creates the audit trigger** that:
   - Fires AFTER UPDATE on the Product table
   - Inserts a record into AuditLog with:
     - `table_name`: 'Product'
     - `record_id`: The old product_id value
     - `action`: 'UPDATE'
     - `timestamp`: CURRENT_TIMESTAMP from SQLite
5. **Returns true** if all operations succeed (checked via `has_value()`), **false** otherwise

The function uses the functional chaining pattern with `and_then()` that's common in the sqlgen library, ensuring that each operation only executes if the previous one succeeded.

