```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace schema_create_view_sales_summary {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct Sale {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  static constexpr bool is_view = true;
  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to database, create tables if needed, and create the view
  // Handle IF NOT EXISTS manually by dropping view first if it exists
  const auto result = 
    sqlgen::sqlite::connect("test_db.sqlite")
      .and_then(create_table<Product> | if_not_exists)
      .and_then(create_table<Sale> | if_not_exists)
      .and_then(execute("DROP VIEW IF EXISTS SalesSummary"))
      .and_then(execute(
        "CREATE VIEW SalesSummary AS "
        "SELECT p.name as product_name, "
        "SUM(s.quantity) as total_quantity, "
        "SUM(s.amount) as total_revenue "
        "FROM Sale s "
        "JOIN Product p ON s.product_id = p.product_id "
        "GROUP BY p.name"
      ));

  return result.has_value();
}

}  // namespace schema_create_view_sales_summary
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using `sqlgen::sqlite::connect()`
2. **Creates the Product and Sale tables** if they don't exist using the `create_table<T> | if_not_exists` pattern
3. **Handles IF NOT EXISTS manually** by first executing `DROP VIEW IF EXISTS SalesSummary` to ensure a clean state
4. **Creates the SalesSummary view** using raw SQL that:
   - Joins Sale (s) and Product (p) tables on product_id
   - Aggregates using SUM() for quantity and amount
   - Groups by product name
   - Aliases the columns as product_name, total_quantity, and total_revenue
5. **Uses monadic chaining** with `and_then()` to handle operations sequentially
6. **Returns true/false** based on whether all operations succeeded (checked via `has_value()`)

The SalesSummary struct is properly marked with `is_view = true` to indicate it's a view rather than a table.

