#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;

  // Connect to the SQLite database
  auto conn = sqlite::connect("test_db.sqlite");

  // Note: SQLite doesn't natively support RIGHT JOIN
  // To simulate "Department RIGHT JOIN Project" (which includes all departments),
  // we would normally use "Project LEFT JOIN Department"
  // However, based on the struct definition where department_name is optional
  // and project_name is not, this appears to return all projects

  // Simulate RIGHT JOIN using LEFT JOIN (all projects with optional department info)
  auto result = conn.and_then([](auto& connection) {
    auto stmt = connection.prepare(
      "SELECT d.name AS department_name, p.name AS project_name "
      "FROM Project p "
      "LEFT JOIN Department d ON p.department_id = d.department_id"
    );

    std::vector<DepProj> results;
    while (stmt.step()) {
      DepProj dp;
      auto dept_name = stmt.template get<std::optional<std::string>>(0);
      dp.department_name = dept_name;
      dp.project_name = stmt.template get<std::string>(1);
      results.push_back(dp);
    }

    return sqlgen::Result<std::vector<DepProj>>(results);
  });

  return result.value_or(std::vector<DepProj>{});
}

}  // namespace right_join_departments_projects
