# Complete Implementation

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen;

  // Open/connect to SQLite database
  auto db = sqlite::open("test_db.sqlite");

  // Create Event table if it doesn't exist
  db.run(CreateTable<Event>{});

  // Insert the provided events into the table
  if (!events.empty()) {
    db.run(Insert<Event>{}.values(events));
  }

  // Build temporal analysis query using SQLite date/time functions
  const std::string query = R"(
    SELECT 
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) as start_day,
      CAST(strftime('%m', start_time) AS INTEGER) as start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) as start_year,
      CAST(strftime('%H', start_time) AS INTEGER) as start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) as start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) as start_second,
      CAST(strftime('%w', start_time) AS INTEGER) as start_weekday,
      unixepoch(start_time) as start_epoch,
      julianday(end_time) - julianday(start_time) as duration_days
    FROM Event
    WHERE end_time IS NOT NULL
  )";

  // Execute query and return results as TemporalAnalysis records
  return db.template query<TemporalAnalysis>(query);
}

}  // namespace analyze_temporal_data
```

## Key Implementation Details:

1. **Database Connection**: Opens SQLite database "test_db.sqlite" using `sqlite::open()`

2. **Table Setup**: Creates the Event table using `CreateTable<Event>{}`

3. **Data Insertion**: Inserts events using `Insert<Event>{}.values(events)`

4. **SQLite Date/Time Functions**:
   - `strftime('%d', start_time)` - Extracts day
   - `strftime('%m', start_time)` - Extracts month
   - `strftime('%Y', start_time)` - Extracts year
   - `strftime('%H', start_time)` - Extracts hour
   - `strftime('%M', start_time)` - Extracts minute
   - `strftime('%S', start_time)` - Extracts second
   - `strftime('%w', start_time)` - Extracts weekday (0-6, 0=Sunday)
   - `unixepoch(start_time)` - Converts to Unix epoch timestamp
   - `julianday(end_time) - julianday(start_time)` - Calculates duration in days

5. **Filtering**: Only returns events with non-null `end_time` values

6. **Type Safety**: Results are automatically mapped to `TemporalAnalysis` struct

