```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;

  // SQLite doesn't support FULL OUTER JOIN natively, so we simulate it using UNION
  // This combines:
  // 1. All suppliers with their matching products (LEFT JOIN)
  // 2. All products without matching suppliers
  const std::string query = 
      "SELECT s.name AS supplier_name, p.name AS product_name "
      "FROM Supplier s "
      "LEFT JOIN Product p ON s.supplier_id = p.supplier_id "
      "UNION ALL "
      "SELECT COALESCE(s.name, '') AS supplier_name, p.name AS product_name "
      "FROM Product p "
      "LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id "
      "WHERE s.supplier_id IS NULL";

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
      .and_then(sqlgen::read<std::vector<SupProd>>(query));

  if (result) {
    return result.value();
  }

  return std::vector<SupProd>{};
}

}  // namespace full_join_suppliers_products
```

This implementation:

1. **Connects to the database**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to connect to the specified SQLite database file

2. **Simulates FULL OUTER JOIN**: Since SQLite doesn't natively support FULL OUTER JOIN, the query uses a UNION of two parts:
   - First part: `LEFT JOIN` from Supplier to Product - gets all suppliers with their products (or NULL if no product)
   - Second part: Products without suppliers (`WHERE s.supplier_id IS NULL`) - gets orphaned products

3. **Returns joined results**: Uses the monadic `.and_then()` pattern with `sqlgen::read<std::vector<SupProd>>()` to execute the query and map results to the SupProd struct

4. **Handles errors**: Returns an empty vector if the operation fails

The query ensures all rows from either table are included in the result set, fulfilling the FULL JOIN requirement.

