};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to in-memory SQLite database and create tables
  auto conn = sqlgen::sqlite::connect()
    .and_then(create_table<Department> | if_not_exists)
    .and_then(create_table<Employee> | if_not_exists);

  if (!conn.has_value()) {
    return analysis;
  }

  // Insert departments
  for (const auto& dept : depts) {
    conn = conn.and_then(insert(dept));
  }

  // Insert employees  
  for (const auto& emp : emps) {
    conn = conn.and_then(insert(emp));
  }

  // INNER JOIN: Get employees with assigned departments
  // SELECT d.department_name, e.first_name, e.last_name, e.salary
  // FROM Department d INNER JOIN Employee e ON d.department_id = e.department_id
  auto inner_results = conn.and_then(execute(
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d INNER JOIN Employee e ON d.department_id = e.department_id"_sql
  )).and_then(read<std::vector<JoinResult>>);

  if (inner_results.has_value()) {
    analysis.inner_join_results = std::move(inner_results.value());
  }

  // LEFT JOIN: Include all employees (even without departments)
  // SELECT d.department_name, e.first_name, e.last_name, e.salary
  // FROM Employee e LEFT JOIN Department d ON e.department_id = d.department_id
  auto left_results = conn.and_then(execute(
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Employee e LEFT JOIN Department d ON e.department_id = d.department_id"_sql
  )).and_then(read<std::vector<JoinResult>>);

  if (left_results.has_value()) {
    analysis.left_join_results = std::move(left_results.value());
  }

  // RIGHT JOIN: Include all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN directly, so we emulate it with LEFT JOIN by swapping tables
  // This is equivalent to: SELECT ... FROM Department d RIGHT JOIN Employee e
  // Implemented as: SELECT ... FROM Department d LEFT JOIN Employee e
  auto right_results = conn.and_then(execute(
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d LEFT JOIN Employee e ON d.department_id = e.department_id"_sql
  )).and_then(read<std::vector<JoinResult>>);

  if (right_results.has_value()) {
    analysis.right_join_results = std::move(right_results.value());
  }

  // FULL OUTER JOIN: Include all employees and departments
  // SQLite doesn't support FULL OUTER JOIN directly, so we emulate it with UNION
  // Combines LEFT JOIN (all employees) with unmatched departments
  auto full_results = conn.and_then(execute(
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Employee e LEFT JOIN Department d ON e.department_id = d.department_id "
    "UNION "
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d LEFT JOIN Employee e ON d.department_id = e.department_id "
    "WHERE e.employee_id IS NULL"_sql
  )).and_then(read<std::vector<JoinResult>>);

  if (full_results.has_value()) {
    analysis.full_join_results = std::move(full_results.value());
  }

  return analysis;
}

}  // namespace analyze_department_employees
