#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace in_operator_usage {

struct Status {
  sqlgen::PrimaryKey<int> id;
  int code;
};

/**
 * This function demonstrates IN operator usage.
 * Returns: std::string.
 */
inline std::string in_operator_usage() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Create a connection
  auto conn = sqlgen::sqlite::connect().value();

  // Variable to store the generated SQL
  std::string generated_sql;

  // Set up trace callback to capture the SQL
  conn.set_trace_callback([&generated_sql](const std::string& sql) {
    generated_sql = sql;
  });

  // Build and execute the query with IN operator
  // This will select from Status where code IN (1, 2, 3)
  conn.and_then(
    read<std::vector<Status>>
    | where("code"_c.in({1, 2, 3}))
  );

  return generated_sql;
}

}  // namespace in_operator_usage
```

