TEST(coalesce_function, test_query_generation) {
    auto query = coalesce_function::coalesce_function();
    std::string sql = sqlgen::sqlite::to_sql(query);

    std::string sql_upper = sql;
    std::transform(sql_upper.begin(), sql_upper.end(), sql_upper.begin(), ::toupper);

    EXPECT_TRUE(sql_upper.find("COALESCE") != std::string::npos || sql_upper.find("IFNULL") != std::string::npos);
    EXPECT_TRUE(sql.find("nickname") != std::string::npos);
    EXPECT_TRUE(sql.find("Anonymous") != std::string::npos);
    EXPECT_TRUE(sql_upper.find("FROM") != std::string::npos);
    EXPECT_TRUE(sql.find("Profile") != std::string::npos);
}

