```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database and execute the query
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  if (!conn) {
    return {};
  }

  // Execute the join query with grouping, ordering, and limit
  auto result = conn.and_then([limit_count](auto db) {
    // Build the SQL query to join Product and Sales tables
    // Calculate total sales, group by product, order by total sales descending
    auto query_str = 
      "SELECT p.product_id, p.product_name, p.category, "
      "SUM(p.price * s.quantity) as total_sales "
      "FROM Product p "
      "INNER JOIN Sales s ON p.product_id = s.product_id "
      "GROUP BY p.product_id, p.product_name, p.category "
      "ORDER BY total_sales DESC "
      "LIMIT " + std::to_string(limit_count);

    return db.template execute<std::vector<TopProduct>>(query_str);
  });

  // Return the results or an empty vector if the query failed
  return result.value_or(std::vector<TopProduct>{});
}

}  // namespace get_top_products
