```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to SQLite database
  auto connector = sqlgen::sqlite::Connector("test_db.sqlite");

  // SQL query to extract weekday from sale_time and aggregate quantities
  // strftime('%w', sale_time) returns weekday as 0-6 (0=Sunday, 1=Monday, ..., 6=Saturday)
  const std::string query = 
    "SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday, "
    "SUM(quantity) AS total_quantity "
    "FROM Sales "
    "GROUP BY strftime('%w', sale_time) "
    "ORDER BY weekday";

  // Execute query and return results
  return connector.query<WeekdayStats>(query);
}

}  // namespace weekday_sales_analysis
```

This implementation:

1. **Connects to the database**: Creates an SQLite connector for "test_db.sqlite"
2. **Extracts weekday**: Uses SQLite's `strftime('%w', sale_time)` function to extract the weekday (0=Sunday through 6=Saturday)
3. **Aggregates totals**: Uses `SUM(quantity)` grouped by weekday to calculate total quantity sold per day of the week
4. **Returns structured data**: Maps the query results to `WeekdayStats` structs and returns them as a vector, ordered by weekday

The query leverages SQLite's date/time functions to parse the timestamp and extract the day of the week, then groups and sums the quantities accordingly.

