# Complete File Contents

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;

  // Connect to SQLite database
  auto session = sqlite::Session("test_db.sqlite");

  // Build SQL query with temporal operations
  // SQLite uses strftime() for date/time extraction and julianday() for date difference
  const std::string query = R"(
    SELECT p.project_id, p.name,
           CAST(strftime('%d', t.start_time) AS INTEGER) as day,
           CAST(strftime('%m', t.start_time) AS INTEGER) as month,
           CAST(strftime('%Y', t.start_time) AS INTEGER) as year,
           CAST(strftime('%H', t.start_time) AS INTEGER) as hour,
           CAST(strftime('%M', t.start_time) AS INTEGER) as minute,
           CAST(strftime('%S', t.start_time) AS INTEGER) as second,
           julianday(t.end_time) - julianday(t.start_time) as duration_days
    FROM Project p
    INNER JOIN TimeLog t ON p.project_id = t.project_id
  )";

  // Execute query and return results mapped to TimeMetrics structure
  return session.query<TimeMetrics>(query);
}

}  // namespace project_time_tracking
```

## Key Implementation Details:

1. **Database Connection**: Creates a SQLite session using `sqlite::Session("test_db.sqlite")`

2. **Temporal Extraction**: Uses SQLite's `strftime()` function to extract date/time components:
   - `%d` for day
   - `%m` for month
   - `%Y` for year
   - `%H` for hour
   - `%M` for minute
   - `%S` for second

3. **Duration Calculation**: Uses `julianday()` function to compute the difference between `end_time` and `start_time` in days

4. **Table JOIN**: Performs an INNER JOIN between Project and TimeLog tables on `project_id`

5. **Type Casting**: Wraps `strftime()` results with `CAST(...AS INTEGER)` to ensure proper integer type mapping

6. **Result Mapping**: The `session.query<TimeMetrics>(query)` method automatically maps the SQL result columns to the `TimeMetrics` struct fields

